import{_ as t,o,c as a,h as n}from"./chunks/framework.3WqHSPpF.js";const p=JSON.parse('{"title":"Getting Started for Product Managers","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/product-managers.md","filePath":"getting-started/product-managers.md"}'),r={name:"getting-started/product-managers.md"};function i(s,e,d,c,l,u){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="getting-started-for-product-managers" tabindex="-1">Getting Started for Product Managers <a class="header-anchor" href="#getting-started-for-product-managers" aria-label="Permalink to &quot;Getting Started for Product Managers&quot;">​</a></h1><p>This guide explains what the Cobalt Design System provides, how it fits into your product workflow, and how to request changes or new components.</p><h2 id="what-cobalt-provides" tabindex="-1">What Cobalt Provides <a class="header-anchor" href="#what-cobalt-provides" aria-label="Permalink to &quot;What Cobalt Provides&quot;">​</a></h2><p>Cobalt is a shared library of reusable UI components, design tokens, and guidelines that product teams use to build consistent interfaces. As a product manager, the design system affects your work in three key areas:</p><ul><li><strong>Faster delivery</strong> — teams spend less time designing and building common UI patterns from scratch.</li><li><strong>Consistent experience</strong> — users see the same interactions and visual language across every product surface.</li><li><strong>Built-in accessibility</strong> — every component meets WCAG 2.1 AA standards, reducing compliance risk.</li></ul><h2 id="how-it-fits-your-workflow" tabindex="-1">How It Fits Your Workflow <a class="header-anchor" href="#how-it-fits-your-workflow" aria-label="Permalink to &quot;How It Fits Your Workflow&quot;">​</a></h2><h3 id="during-discovery" tabindex="-1">During Discovery <a class="header-anchor" href="#during-discovery" aria-label="Permalink to &quot;During Discovery&quot;">​</a></h3><p>When scoping a feature, check the Cobalt component library first. Many common patterns are already solved:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Cobalt Component</th><th>Notes</th></tr></thead><tbody><tr><td>Form inputs</td><td><code>co-input</code>, <code>co-select</code>, <code>co-checkbox</code></td><td>Includes built-in validation and error states</td></tr><tr><td>Actions</td><td><code>co-button</code>, <code>co-icon-button</code></td><td>Primary, secondary, ghost, and danger variants</td></tr><tr><td>Feedback</td><td><code>co-toast</code>, <code>co-alert</code>, <code>co-dialog</code></td><td>Covers success, warning, error, and info scenarios</td></tr><tr><td>Navigation</td><td><code>co-tabs</code>, <code>co-breadcrumb</code>, <code>co-sidebar</code></td><td>Responsive by default</td></tr><tr><td>Data display</td><td><code>co-table</code>, <code>co-card</code>, <code>co-badge</code></td><td>Sortable tables, status badges</td></tr></tbody></table><p>Using existing components means less design and engineering effort, which translates to smaller estimates and faster time-to-market.</p><h3 id="during-design-review" tabindex="-1">During Design Review <a class="header-anchor" href="#during-design-review" aria-label="Permalink to &quot;During Design Review&quot;">​</a></h3><p>Look for these signals that the design is aligned with Cobalt:</p><ol><li>Components match their Cobalt counterparts in Figma.</li><li>Colors, spacing, and typography use named tokens — not arbitrary values.</li><li>Interactive states (hover, focus, disabled, error) are accounted for.</li><li>The design includes responsive considerations for mobile, tablet, and desktop.</li></ol><blockquote><p><strong>Tip:</strong> If a design introduces a pattern that looks custom, ask whether an existing Cobalt component could cover the use case. Custom components add maintenance cost and slow down future redesigns.</p></blockquote><h3 id="during-development" tabindex="-1">During Development <a class="header-anchor" href="#during-development" aria-label="Permalink to &quot;During Development&quot;">​</a></h3><p>Cobalt components are production-ready. When engineering picks up a story, they import the component and configure it with props — they do not rebuild it. This means:</p><ul><li>Fewer bugs related to UI behavior.</li><li>Shorter code review cycles for UI-heavy features.</li><li>Consistent behavior across teams without extra coordination.</li></ul><h2 id="requesting-new-components" tabindex="-1">Requesting New Components <a class="header-anchor" href="#requesting-new-components" aria-label="Permalink to &quot;Requesting New Components&quot;">​</a></h2><p>Not every pattern exists in Cobalt yet. When you identify a gap, here is the process for requesting a new component or enhancement.</p><h3 id="step-1-—-check-existing-components" tabindex="-1">Step 1 — Check Existing Components <a class="header-anchor" href="#step-1-—-check-existing-components" aria-label="Permalink to &quot;Step 1 — Check Existing Components&quot;">​</a></h3><p>Search the <a href="/cobalt-design-system/components/button.html">component documentation</a> to confirm the pattern is not already covered. Sometimes an existing component with different props can solve the use case.</p><h3 id="step-2-—-submit-a-request" tabindex="-1">Step 2 — Submit a Request <a class="header-anchor" href="#step-2-—-submit-a-request" aria-label="Permalink to &quot;Step 2 — Submit a Request&quot;">​</a></h3><p>Open a request in the <code>cobalt-design-system</code> GitHub repository using the <strong>Component Request</strong> issue template. Include:</p><ul><li><strong>Use case:</strong> What problem does this component solve?</li><li><strong>Scope:</strong> Which products or teams need it?</li><li><strong>Priority:</strong> Is this blocking a launch or a nice-to-have?</li><li><strong>Examples:</strong> Screenshots, competitor references, or links to designs.</li></ul><h3 id="step-3-—-review-and-prioritization" tabindex="-1">Step 3 — Review and Prioritization <a class="header-anchor" href="#step-3-—-review-and-prioritization" aria-label="Permalink to &quot;Step 3 — Review and Prioritization&quot;">​</a></h3><p>The Cobalt team reviews requests on a two-week cadence. Requests are evaluated against these criteria:</p><table tabindex="0"><thead><tr><th>Criteria</th><th>Weight</th><th>Description</th></tr></thead><tbody><tr><td>Cross-team demand</td><td>High</td><td>Is this needed by more than one product team?</td></tr><tr><td>User impact</td><td>High</td><td>Does this affect a core workflow or conversion path?</td></tr><tr><td>Complexity</td><td>Medium</td><td>How much design and engineering effort is required?</td></tr><tr><td>Workaround availability</td><td>Medium</td><td>Can teams use an existing component as a stopgap?</td></tr><tr><td>Strategic alignment</td><td>Low</td><td>Does this support a broader platform initiative?</td></tr></tbody></table><h3 id="step-4-—-tracking" tabindex="-1">Step 4 — Tracking <a class="header-anchor" href="#step-4-—-tracking" aria-label="Permalink to &quot;Step 4 — Tracking&quot;">​</a></h3><p>Accepted requests appear on the Cobalt roadmap board. You will receive status updates in the GitHub issue and in <code>#cobalt-announcements</code> on Slack.</p><h2 id="governance-model" tabindex="-1">Governance Model <a class="header-anchor" href="#governance-model" aria-label="Permalink to &quot;Governance Model&quot;">​</a></h2><p>Cobalt is maintained by a dedicated design system team, but it is governed collaboratively:</p><ul><li><strong>Design System Team</strong> — owns the codebase, reviews contributions, publishes releases, and maintains documentation.</li><li><strong>Product Teams</strong> — submit requests, contribute components, and provide feedback on existing patterns.</li><li><strong>Design Council</strong> — a rotating group of senior designers and PMs who meet monthly to review the roadmap and resolve cross-team conflicts.</li></ul><h3 id="contributing-a-component" tabindex="-1">Contributing a Component <a class="header-anchor" href="#contributing-a-component" aria-label="Permalink to &quot;Contributing a Component&quot;">​</a></h3><p>Product teams can contribute components directly. The process is:</p><ol><li>Propose the component via a GitHub issue.</li><li>The design system team provides a spec review and API guidance.</li><li>The product team builds the component following Cobalt conventions.</li><li>The design system team reviews, tests, and merges the contribution.</li></ol><blockquote><p><strong>Warning:</strong> Components that are merged into Cobalt become the responsibility of the design system team. Make sure the use case is general enough to justify long-term maintenance.</p></blockquote><h2 id="measuring-impact" tabindex="-1">Measuring Impact <a class="header-anchor" href="#measuring-impact" aria-label="Permalink to &quot;Measuring Impact&quot;">​</a></h2><p>Track the value of the design system with these metrics:</p><ul><li><strong>Adoption rate</strong> — percentage of product surfaces using Cobalt components.</li><li><strong>Time-to-ship</strong> — compare feature delivery timelines before and after adoption.</li><li><strong>Bug density</strong> — UI-related bug count in Cobalt components vs. custom implementations.</li><li><strong>Consistency score</strong> — periodic audits measuring visual and interaction consistency across products.</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Component Library:</strong> <a href="/cobalt-design-system/components/button.html">Browse Components</a></li><li><strong>Roadmap:</strong> <code>cobalt-design-system</code> GitHub project board</li><li><strong>Slack:</strong> <code>#cobalt-support</code> for questions, <code>#cobalt-announcements</code> for release updates</li><li><strong>Office Hours:</strong> Wednesdays 2-3 PM ET — open to all roles</li></ul>',41)])])}const g=t(r,[["render",i]]);export{p as __pageData,g as default};
